            const parentSelect = getEl('tree-node-parent');
            if (!listEl || !parentSelect) return;
            
            listEl.innerHTML = '';
            parentSelect.innerHTML = '<option value="root">Ninguno (Es el Efecto Final / Lesión)</option>';
            
