            const nd = parseInt(document.getElementById('risk-nd').value);
            const ne = parseInt(document.getElementById('risk-ne').value);
            const nc = parseInt(document.getElementById('risk-nc').value);

            const np = nd * ne;
            document.getElementById('risk-np').value = np;
