        function handleDrop(e, targetCol) {
            e.preventDefault();
            const id = e.dataTransfer.getData('text/plain');
            const task = currentWizard.tasks.find(t => t.id.toString() === id.toString());
            if (task && task.column !== targetCol) {
                task.column = targetCol;
                renderKanban();
                saveLocalData();
            }
        }

