        function cleanAndParseJSON(text) {
            let cleanText = text.trim();
            if (cleanText.startsWith("\`\`\`")) {
                cleanText = cleanText.replace(/^\`\`\`(?:json)?/i, "").replace(/\`\`\`$/, "").trim();
            }
            try {
                return JSON.parse(cleanText);
            } catch (e) {
                const firstBrace = cleanText.indexOf('{');
                const lastBrace = cleanText.lastIndexOf('}');
                if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
                    const potentialJSON = cleanText.substring(firstBrace, lastBrace + 1);
                    try {
                        return JSON.parse(potentialJSON);
                    } catch (innerError) {
                        console.error("Failed to parse extracted JSON substring:", innerError);
                    }
                }
                const firstBracket = cleanText.indexOf('[');
                const lastBracket = cleanText.lastIndexOf(']');
                if (firstBracket !== -1 && lastBracket !== -1 && lastBracket > firstBracket) {
                    const potentialJSON = cleanText.substring(firstBracket, lastBracket + 1);
                    try {
                        return JSON.parse(potentialJSON);
                    } catch (innerError) {
                        console.error("Failed to parse extracted Array substring:", innerError);
                    }
                }
                throw e;
            }
        }
