        function safeGetLocalStorage(key) {
            try {
                return localStorage.getItem(key);
            } catch (e) {
                console.warn("localStorage.getItem blocked:", e);
                return null;
            }
        }

        function safeSetLocalStorage(key, value) {
            try {
                localStorage.setItem(key, value);
            } catch (e) {
                console.warn("localStorage.setItem blocked:", e);
            }
        }

        function safeRemoveLocalStorage(key) {
            try {
                localStorage.removeItem(key);
            } catch (e) {
                console.warn("localStorage.removeItem blocked:", e);
            }
        }

        window.onload = async function() {
            // Migration: Clean up old local storage items to bypass QuotaExceededError
            try {
                const localLogo = safeGetLocalStorage('wappy_sst_global_logo');
                if (localLogo) {
                    await saveGlobalLogoToDB(localLogo);
                    safeRemoveLocalStorage('wappy_sst_global_logo');
                }
            } catch(e) {}

            try {
                for (let i = 0; i < localStorage.length; i++) {
                    const key = localStorage.key(i);
                    if (key && key.startsWith('wappy_sst_')) {
                        const val = safeGetLocalStorage(key);
                        if (val && (val.includes('data:image/') || val.includes('data:audio/') || val.includes('data:video/'))) {
                            try {
                                const data = JSON.parse(val);
                                let modified = false;
                                if (data.currentWizard) {
                                    if (data.currentWizard.photos) { delete data.currentWizard.photos; modified = true; }
                                    if (data.currentWizard.audioBase64) { delete data.currentWizard.audioBase64; modified = true; }
                                    if (data.currentWizard.videoBase64) { delete data.currentWizard.videoBase64; modified = true; }
                                }
                                if (data.appDocHeader && data.appDocHeader.logoBase64) {
                                    await saveGlobalLogoToDB(data.appDocHeader.logoBase64);
                                    delete data.appDocHeader.logoBase64;
                                    modified = true;
                                }
                                if (modified) {
                                    safeSetLocalStorage(key, JSON.stringify(data));
                                }
                            } catch (e) {}
                        }
                    }
                }
            } catch (e) { console.error("Error migrating localStorage:", e); }

            try {
                if (typeof lucide !== 'undefined' && lucide.createIcons) {
                    lucide.createIcons();
                }
            } catch (e) { console.error("Error creating Lucide icons:", e); }
            
            try {
                initializeCanvas();
            } catch (e) { console.error("Error initializing signature canvas:", e); }
            
            try {
                await loadState();
            } catch (e) { console.error("Error loading state:", e); }
            
            // Set export date default
            try {
                const today = new Date().toISOString().split('T')[0];
                const exportDateEl = document.getElementById('export-date');
                if (exportDateEl && !exportDateEl.value) {
                    exportDateEl.value = today;
                }
            } catch (e) { console.error("Error setting default export date:", e); }
        }

