        function handleImageUpload(event) {
            const files = event.target.files;
            if (!files) return;
            const remaining = 3 - currentWizard.photos.length;
            const count = Math.min(files.length, remaining);
            let processed = 0;
            if (count <= 0) {
                alert('Límite de 3 fotos alcanzado.');
                return;
            }
            for (let i = 0; i < count; i++) {
                const file = files[i];
                const reader = new FileReader();
                reader.onload = function(e) {
                    currentWizard.photos.push(e.target.result);
                    processed++;
                    if (processed === count) {
                        renderPhotos();
                        saveLocalData();
                    }
                };
                reader.readAsDataURL(file);
            }
        }

