        let audioRecorder = null;
        let audioChunks = [];

        async function toggleAudioRecording() {
            const btn = getEl('btn-audio-record');
            if (!btn) return;
            if (audioRecorder && audioRecorder.state === 'recording') {
                audioRecorder.stop();
                btn.innerText = 'Iniciar Grabación';
                btn.classList.remove('bg-red-500', 'text-white');
                btn.classList.add('bg-emerald-500/10', 'text-emerald-600');
            } else {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
                    audioChunks = [];
                    audioRecorder = new MediaRecorder(stream);
                    audioRecorder.ondataavailable = e => audioChunks.push(e.data);
                    audioRecorder.onstop = () => {
                        const blob = new Blob(audioChunks, { type: 'audio/mp3' });
                        const reader = new FileReader();
                        reader.onload = e => {
                            currentWizard.audioBase64 = e.target.result;
                            renderAudio();
                            saveLocalData();
                        };
                        reader.readAsDataURL(blob);
                        stream.getTracks().forEach(track => track.stop());
                    };
                    audioRecorder.start();
                    btn.innerText = 'Detener Grabación...';
                    btn.classList.remove('bg-emerald-500/10', 'text-emerald-600');
                    btn.classList.add('bg-red-500', 'text-white');
                } catch(e) {
                    console.error("Audio recording failed, fallback to upload", e);
                    alert("No se pudo acceder al micrófono. Por favor, suba un archivo de audio.");
                }
            }
        }

        function handleAudioUpload(event) {
            const file = event.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = e => {
                currentWizard.audioBase64 = e.target.result;
                renderAudio();
                saveLocalData();
            };
            reader.readAsDataURL(file);
        }

        function deleteAudio() {
            currentWizard.audioBase64 = "";
            renderAudio();
            saveLocalData();
        }

        function renderAudio() {
            const player = getEl('audio-playback');
            const delBtn = getEl('btn-delete-audio');
            if (!player || !delBtn) return;
            if (currentWizard.audioBase64) {
                player.src = currentWizard.audioBase64;
                player.classList.remove('hidden');
                delBtn.classList.remove('hidden');
            } else {
                player.src = "";
                player.classList.add('hidden');
                delBtn.classList.add('hidden');
            }
            updateSummaryAudioVideo();
        }

        let videoRecorder = null;
        let videoChunks = [];
        let videoTimerInterval = null;

        async function startVideoRecording() {
            const btn = getEl('btn-video-record');
            const timer = getEl('video-timer');
            if (!btn || !timer) return;
            
            try {
                const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
                videoChunks = [];
                videoRecorder = new MediaRecorder(stream);
                videoRecorder.ondataavailable = e => videoChunks.push(e.data);
                videoRecorder.onstop = () => {
                    const blob = new Blob(videoChunks, { type: 'video/mp4' });
                    const reader = new FileReader();
                    reader.onload = e => {
                        currentWizard.videoBase64 = e.target.result;
                        renderVideo();
                        saveLocalData();
                    };
                    reader.readAsDataURL(blob);
                    stream.getTracks().forEach(track => track.stop());
                };
                
                videoRecorder.start();
                btn.innerText = 'Grabando...';
                btn.disabled = true;
                timer.classList.remove('hidden');
                
                let seconds = 10;
                timer.innerText = "00:10";
                videoTimerInterval = setInterval(() => {
                    seconds--;
                    timer.innerText = "00:0" + seconds;
                    if (seconds <= 0) {
                        clearInterval(videoTimerInterval);
                        if (videoRecorder && videoRecorder.state === 'recording') {
                            videoRecorder.stop();
                        }
                        btn.innerText = 'Grabar Video 10s';
                        btn.disabled = false;
                        timer.classList.add('hidden');
                    }
                }, 1000);
            } catch(e) {
                console.error("Video recording failed, fallback to upload", e);
                alert("No se pudo acceder a la cámara. Por favor, suba un archivo de video.");
            }
        }

        function handleVideoUpload(event) {
            const file = event.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = e => {
                currentWizard.videoBase64 = e.target.result;
                renderVideo();
                saveLocalData();
            };
            reader.readAsDataURL(file);
        }

