        function addWitness() {
            const nameEl = getEl('witness-name-input');
            const docEl = getEl('witness-doc-input');
            const testimonyEl = getEl('witness-testimony-input');
            if (!nameEl || !docEl || !testimonyEl) return;
            const name = nameEl.value.trim();
            const doc = docEl.value.trim();
            const testimony = testimonyEl.value.trim();
            if (!name) {
                alert('Debe ingresar al menos el nombre del testigo.');
                return;
            }
            currentWizard.witnesses.push({ name, doc, testimony });
            nameEl.value = '';
            docEl.value = '';
            testimonyEl.value = '';
            renderWitnesses();
            saveLocalData();
        }

