        function initializeSingleCanvas(cvs) {
            const context = cvs.getContext('2d');
            context.strokeStyle = '#1e293b';
            context.lineWidth = 2.5;
            context.lineCap = 'round';
            context.lineJoin = 'round';
            
            cvs.isDrawing = false;
            if (cvs.hasDrawn === undefined) {
                cvs.hasDrawn = false;
            }
            
            cvs.addEventListener('mousedown', (e) => {
                cvs.isDrawing = true;
                context.beginPath();
                const rect = cvs.getBoundingClientRect();
                context.moveTo(e.clientX - rect.left, e.clientY - rect.top);
            });
            
            cvs.addEventListener('mousemove', (e) => {
                if (!cvs.isDrawing) return;
                cvs.hasDrawn = true;
                const rect = cvs.getBoundingClientRect();
                context.lineTo(e.clientX - rect.left, e.clientY - rect.top);
                context.stroke();
            });
            
            const stopDrawing = () => {
                cvs.isDrawing = false;
                context.closePath();
                saveLocalData();
            };
            
            cvs.addEventListener('mouseup', stopDrawing);
            cvs.addEventListener('mouseleave', stopDrawing);
            
            cvs.addEventListener('touchstart', (e) => {
                cvs.isDrawing = true;
                context.beginPath();
                const rect = cvs.getBoundingClientRect();
                const touch = e.touches[0];
                context.moveTo(touch.clientX - rect.left, touch.clientY - rect.top);
                e.preventDefault();
            }, { passive: false });
            
            cvs.addEventListener('touchmove', (e) => {
                if (!cvs.isDrawing) return;
                cvs.hasDrawn = true;
                const rect = cvs.getBoundingClientRect();
                const touch = e.touches[0];
                context.lineTo(touch.clientX - rect.left, touch.clientY - rect.top);
                context.stroke();
                e.preventDefault();
            }, { passive: false });

            cvs.addEventListener('touchend', stopDrawing);
            cvs.addEventListener('touchcancel', stopDrawing);
        }

        function initializeCanvas() {
            document.querySelectorAll('canvas').forEach(cvs => {
                initializeSingleCanvas(cvs);
            });
        }

        function clearSignatureCanvas(canvasId) {
            const cvs = document.getElementById(canvasId || 'signature-canvas');
            if (cvs) {
                const context = cvs.getContext('2d');
                context.clearRect(0, 0, cvs.width, cvs.height);
                context.beginPath();
                cvs.hasDrawn = false;
                saveLocalData();
            }
        }

        function uploadSignatureImage(canvasId) {
            const fileInput = document.getElementById('upload-sig-' + canvasId);
            if (fileInput && fileInput.files && fileInput.files[0]) {
                const file = fileInput.files[0];
                const reader = new FileReader();
                reader.onload = function(e) {
                    const img = new Image();
                    img.onload = function() {
                        const cvs = document.getElementById(canvasId);
                        if (cvs) {
                            const ctx = cvs.getContext('2d');
                            ctx.clearRect(0, 0, cvs.width, cvs.height);
                            const ratio = Math.min(cvs.width / img.width, cvs.height / img.height);
                            const w = img.width * ratio;
                            const h = img.height * ratio;
                            const x = (cvs.width - w) / 2;
                            const y = (cvs.height - h) / 2;
                            ctx.drawImage(img, x, y, w, h);
                            cvs.hasDrawn = true;
                            saveLocalData();
                        }
                    };
                    img.src = e.target.result;
                };
                reader.readAsDataURL(file);
            }
        }

